import{_ as r,o as a,c as d,ag as e}from"./chunks/framework.CNG7EpJN.js";const b=JSON.parse('{"title":"オーナーダッシュボード","description":"","frontmatter":{"title":"オーナーダッシュボード"},"headers":[],"relativePath":"tenant/15-owner.md","filePath":"tenant/15-owner.md"}'),o={name:"tenant/15-owner.md"};function n(l,t,i,s,h,c){return a(),d("div",null,[...t[0]||(t[0]=[e('<h1 id="_15-オーナーダッシュボード" tabindex="-1">15. オーナーダッシュボード <a class="header-anchor" href="#_15-オーナーダッシュボード" aria-label="Permalink to &quot;15. オーナーダッシュボード&quot;">​</a></h1><p>オーナーダッシュボードは、複数店舗の管理、本部機能、ユーザー管理、契約・決済設定を行う画面です。オーナーロールのユーザーが利用します。</p><h2 id="画面の構成-10の主要機能" tabindex="-1">画面の構成（10の主要機能） <a class="header-anchor" href="#画面の構成-10の主要機能" aria-label="Permalink to &quot;画面の構成（10の主要機能）&quot;">​</a></h2><p>最新のオーナーダッシュボードは、左側のナビゲーションから以下の10個の機能に素早くアクセスできます。</p><table tabindex="0"><thead><tr><th>タブ名称</th><th>内容</th></tr></thead><tbody><tr><td><strong>クロス店舗レポート</strong></td><td>全店舗の売上、客数、客単価、回転率を横並びで比較分析します。</td></tr><tr><td><strong>ABC分析</strong></td><td>全店舗または指定店舗の商品別貢献度をA/B/Cランクで可視化します。</td></tr><tr><td><strong>シフト概況</strong></td><td>各店舗の人件費、労働時間、充足率、ヘルプ要請状況を把握します。</td></tr><tr><td><strong>本部メニュー</strong></td><td>チェーン共通のマスタメニューを作成し、各店舗へ一括配信します。</td></tr><tr><td><strong>店舗管理</strong></td><td>新規店舗の追加、既存店舗の設定変更、休業・削除を管理します。</td></tr><tr><td><strong>ユーザー管理</strong></td><td>オーナー、マネージャー、スタッフ、端末用アカウントを作成・編集します。</td></tr><tr><td><strong>AIアシスタント</strong></td><td>SNS投稿案の作成、売上分析、需要予測、競合調査などをAIが支援します。</td></tr><tr><td><strong>契約・プラン</strong></td><td>POSLAの月額利用料、トライアル期間、アドオン（本部配信）を管理します。</td></tr><tr><td><strong>決済設定</strong></td><td>Stripe Connect の連携や、テナント独自の決済キーを設定します。</td></tr><tr><td><strong>外部連携</strong></td><td>LINE公式アカウントとの接続設定、友だち紐付け、スマレジ連携を管理します。</td></tr></tbody></table><h2 id="外部連携-line-スマレジ" tabindex="-1">外部連携（LINE / スマレジ） <a class="header-anchor" href="#外部連携-line-スマレジ" aria-label="Permalink to &quot;外部連携（LINE / スマレジ）&quot;">​</a></h2><p>「外部連携」タブでは、店舗運営を加速させる外部サービスとの接続を一元管理します。</p><ul><li><strong>LINE公式アカウント</strong>: 予約確定、リマインド、テイクアウト準備完了などの通知（LINE v1）を自動送信するための設定を行います。 <ul><li>※リッチメニュー、LIFF、メッセージ配信、チャットボット等の機能（LINE v2）は、現在開発中のバックログであり未提供です。</li></ul></li><li><strong>スマレジ連携</strong>: POSLAでの注文データをスマレジへ自動送信し、売上管理を統合します。</li></ul><h2 id="契約と決済" tabindex="-1">契約と決済 <a class="header-anchor" href="#契約と決済" aria-label="Permalink to &quot;契約と決済&quot;">​</a></h2><p>「契約・プラン」および「決済設定」はオーナーのみがアクセス可能な重要項目です。</p><ul><li>クレジットカードの更新やプランの変更は「契約・プラン」から行います。</li><li>お客様のセルフ決済を有効にするための Stripe 連携は「決済設定」から行います。</li></ul><h2 id="店舗を追加する" tabindex="-1">店舗を追加する <a class="header-anchor" href="#店舗を追加する" aria-label="Permalink to &quot;店舗を追加する&quot;">​</a></h2><ol><li>店舗管理を開きます。</li><li>店舗名、住所、営業時間、税率などを入力します。</li><li>保存後、必要なマネージャーを所属させます。</li><li>店舗側でメニュー、テーブル、決済、プリンタを設定します。</li></ol><h2 id="ユーザー管理" tabindex="-1">ユーザー管理 <a class="header-anchor" href="#ユーザー管理" aria-label="Permalink to &quot;ユーザー管理&quot;">​</a></h2><p>オーナーは全店舗のユーザーを管理できます。退職者や異動者がいる場合は、速やかにアカウントを無効化または所属店舗を変更してください。</p><h2 id="複数店舗レポート" tabindex="-1">複数店舗レポート <a class="header-anchor" href="#複数店舗レポート" aria-label="Permalink to &quot;複数店舗レポート&quot;">​</a></h2><p>店舗別売上、商品傾向、スタッフ実績を横断して確認できます。期間と対象店舗をそろえて比較してください。</p><h2 id="困ったとき" tabindex="-1">困ったとき <a class="header-anchor" href="#困ったとき" aria-label="Permalink to &quot;困ったとき&quot;">​</a></h2><table tabindex="0"><thead><tr><th>症状</th><th>対処</th></tr></thead><tbody><tr><td>店舗が表示されない</td><td>店舗の登録状態と契約内容を確認してください。</td></tr><tr><td>ユーザーがログインできない</td><td>所属店舗、ロール、パスワードを確認してください。</td></tr><tr><td>本部メニューが使えない</td><td>契約プランまたはオプションを確認してください。</td></tr><tr><td>決済設定が進まない</td><td>入力内容を確認し、必要に応じてPOSLAサポートへお問い合わせください。</td></tr></tbody></table>',19)])])}const g=r(o,[["render",n]]);export{b as __pageData,g as default};
